import 'package:flutter/material.dart';import 'package:go_router/go_router.dart';import '../../core/utils/validators.dart';import '../../core/widgets/app_button.dart';import '../../core/widgets/app_text_field.dart';import '../../services/auth_service.dart';
class LoginScreen extends StatefulWidget{final String? redirect;const LoginScreen({super.key,this.redirect});@override State<LoginScreen> createState()=>_LoginScreenState();}
class _LoginScreenState extends State<LoginScreen>{final f=GlobalKey<FormState>(),e=TextEditingController(),p=TextEditingController();bool loading=false;String? error;@override Widget build(BuildContext c)=>Scaffold(appBar:AppBar(title:const Text('Login')),body:Form(key:f,child:ListView(padding:const EdgeInsets.all(16),children:[AppTextField(controller:e,label:'Email',keyboardType:TextInputType.emailAddress,validator:Validators.email),const SizedBox(height:12),AppTextField(controller:p,label:'Password',obscure:true,validator:(v)=>Validators.required(v,'Password')),if(error!=null)Text(error!,style:const TextStyle(color:Colors.redAccent)),AppButton(label:'Login',loading:loading,onPressed:()async{if(!f.currentState!.validate())return;setState(()=>loading=true);try{await AuthService().login(e.text,p.text);if(c.mounted)c.go(widget.redirect??'/home');}catch(ex){setState(()=>error='Login failed. Check your email and password.');}finally{if(mounted)setState(()=>loading=false);}}),TextButton(onPressed:()=>c.go('/register${widget.redirect==null?'':'?redirect=${Uri.encodeComponent(widget.redirect!)}'}'),child:const Text('Create account'))])));}
